SELECT DISTINCT ?algorithm ?algorithmLabel WHERE {
  ?contribution a orkgc:C121001 ;
    orkgp:P181046 ?approach .
  ?approach orkgp:P41835 ?documentationType ;
    orkgp:P58069 ?algorithm .
  OPTIONAL { ?algorithm rdfs:label ?algorithmLabel . }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
