PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT (COALESCE(?validationProcedureLabel, STR(?validationProcedure)) AS ?validationProcedureValue) WHERE {
  ?contribution a orkgc:C121001 ;
    orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P181051 ?baselineComparison ;
    orkgp:P181050 ?validationProcedure .
  OPTIONAL { ?validationProcedure rdfs:label ?validationProcedureLabel . }
}

