SELECT DISTINCT (COALESCE(?establishmentLabel, STR(?establishment)) AS ?establishmentValue) WHERE {
  ?contribution a orkgc:C121001 ;
    orkgp:P181031 ?annotationProcess .
  ?annotationProcess orkgp:P181032 ?annotator ;
    orkgp:P181036 ?annotationScheme .
  ?annotator orkgp:P59120 ?numAnnotators .
  FILTER(?numAnnotators = 2)
  ?annotationScheme orkgp:P181037 ?establishment .
  OPTIONAL { ?establishment rdfs:label ?establishmentLabel . }
}

