PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (MIN(xsd:integer(?year)) AS ?earliestYear) WHERE {
  SELECT DISTINCT ?paper ?year WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 .
    ?paper orkgp:P29 ?year .
    ?contribution orkgp:P39099 ?thr .
    ?thr orkgp:P145000 ?mentioned .
    FILTER NOT EXISTS { ?thr orkgp:P55037 ?cv . }
    FILTER NOT EXISTS { ?thr orkgp:P55035 ?iv . }
    FILTER NOT EXISTS { ?thr orkgp:P55034 ?ev . }
    FILTER NOT EXISTS { ?thr orkgp:P55036 ?clv . }
    FILTER NOT EXISTS { ?thr orkgp:P59109 ?rel . }
    FILTER NOT EXISTS { ?thr orkgp:P60006 ?gen . }
    FILTER NOT EXISTS { ?thr orkgp:P97002 ?rep . }
    FILTER NOT EXISTS { ?thr orkgp:P68005 ?cont . }
    FILTER NOT EXISTS { ?thr orkgp:P97000 ?desc . }
    FILTER NOT EXISTS { ?thr orkgp:P97001 ?theo . }
  }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?paper ?paperLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  {
    ?contribution orkgp:P15124 ?da .
    ?da orkgp:P56048 ?desc .
  }
  UNION
  {
    ?contribution orkgp:P15124 ?da .
    ?da orkgp:P57016 ?ml .
  }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY ?paper
LIMIT 10

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(DISTINCT ?paper) AS ?count) WHERE {
  {
    SELECT ?paper WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C27001 .
      ?contribution orkgp:P56008 ?dc .
      ?dc orkgp:P1005 ?method .
    }
    GROUP BY ?paper
    HAVING(COUNT(DISTINCT ?method) > 1)
  }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?paper ?paperLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P56008 ?dc .
  ?dc orkgp:P1005 ?method .
  FILTER NOT EXISTS {
    ?method orkgp:P94003 ?methodType .
  }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?paper ?paperLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  FILTER EXISTS { ?contribution orkgp:P37330 ?rq . }
  FILTER EXISTS { ?contribution orkgp:P57004 ?rqa . }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P39099 ?threats .
  ?threats orkgp:P145000 ?mentioned .
  FILTER NOT EXISTS { ?threats orkgp:P55037 ?x1 . }
  FILTER NOT EXISTS { ?threats orkgp:P55035 ?x2 . }
  FILTER NOT EXISTS { ?threats orkgp:P55034 ?x3 . }
  FILTER NOT EXISTS { ?threats orkgp:P55036 ?x4 . }
  FILTER NOT EXISTS { ?threats orkgp:P59109 ?x5 . }
  FILTER NOT EXISTS { ?threats orkgp:P60006 ?x6 . }
  FILTER NOT EXISTS { ?threats orkgp:P97002 ?x7 . }
  FILTER NOT EXISTS { ?threats orkgp:P68005 ?x8 . }
  FILTER NOT EXISTS { ?threats orkgp:P97000 ?x9 . }
  FILTER NOT EXISTS { ?threats orkgp:P97001 ?x10 . }
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?paper ?paperLabel
WHERE {
  {
    SELECT ?paper (COUNT(DISTINCT ?cat) AS ?catCount)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C27001 .
      ?contribution orkgp:P15124 ?da .
      ?da orkgp:P56048 ?ds .
      {
        ?ds orkgp:P56049 ?x .
        BIND("frequency" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57005 ?x .
        BIND("central" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57008 ?x .
        BIND("dispersion" AS ?cat)
      }
      UNION {
        ?ds orkgp:P57010 ?x .
        BIND("position" AS ?cat)
      }
    }
    GROUP BY ?paper
  }
  {
    SELECT (MAX(?catCountInner) AS ?maxCount)
    WHERE {
      {
        SELECT ?paperInner (COUNT(DISTINCT ?catInner) AS ?catCountInner)
        WHERE {
          ?paperInner orkgp:P31 ?contributionInner .
          ?contributionInner a orkgc:C27001 .
          ?contributionInner orkgp:P15124 ?daInner .
          ?daInner orkgp:P56048 ?dsInner .
          {
            ?dsInner orkgp:P56049 ?xInner .
            BIND("frequency" AS ?catInner)
          }
          UNION {
            ?dsInner orkgp:P57005 ?xInner .
            BIND("central" AS ?catInner)
          }
          UNION {
            ?dsInner orkgp:P57008 ?xInner .
            BIND("dispersion" AS ?catInner)
          }
          UNION {
            ?dsInner orkgp:P57010 ?xInner .
            BIND("position" AS ?catInner)
          }
        }
        GROUP BY ?paperInner
      }
    }
  }
  FILTER(?catCount = ?maxCount)
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?paper ?paperLabel ?agreement WHERE {
  {
    SELECT ?paper (MAX(xsd:decimal(?a)) AS ?agreement) WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 .
      ?contribution orkgp:P181031 ?annotationProcess .
      ?annotationProcess orkgp:P181041 ?agreementStmt .
      ?agreementStmt orkgp:P181045 ?a .
    }
    GROUP BY ?paper
  }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
}
ORDER BY DESC(?agreement)
LIMIT 10

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT (COUNT(DISTINCT ?paper) AS ?count) WHERE {
  {
    SELECT ?paper WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 .
      ?contribution orkgp:HAS_EVALUATION ?evaluation .
      ?evaluation orkgp:P110006 ?metric .
    }
    GROUP BY ?paper
    HAVING(COUNT(DISTINCT ?metric) > 1)
  }
}

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?paper ?paperLabel WHERE {
  {
    SELECT ?paper WHERE {
      ?paper orkgp:P31 ?contribution .
      ?contribution a orkgc:C121001 .
      ?contribution orkgp:P181011 ?dataset .
      ?dataset orkgp:P181017 ?source .
      ?source orkgp:P181019 ?numSources .
      ?source orkgp:P181020 ?domain .
      FILTER(xsd:decimal(?numSources) > 1)
    }
    GROUP BY ?paper
  }
  OPTIONAL { ?paper rdfs:label ?paperLabel }
}

