PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?measureLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P15124 ?da .
  ?da orkgp:P56048 ?desc .
  ?desc orkgp:P57005 ?ct .
  { ?ct orkgp:P47000 ?measure . ?measure rdfs:label ?measureLabel . }
  UNION
  { ?ct orkgp:P57006 ?measure . ?measure rdfs:label ?measureLabel . }
  UNION
  { ?ct orkgp:P57007 ?measure . ?measure rdfs:label ?measureLabel . }
  UNION
  { ?ct orkgp:P44107 ?measure . ?measure rdfs:label ?measureLabel . }
  UNION
  { ?ct orkgp:P44108 ?measure . ?measure rdfs:label ?measureLabel . }
}
ORDER BY ?measureLabel

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?mentionedLabel WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C27001 .
  ?contribution orkgp:P39099 ?thr .
  ?thr orkgp:P145000 ?mentioned .
  FILTER NOT EXISTS { ?thr orkgp:P55037 ?cv . }
  FILTER NOT EXISTS { ?thr orkgp:P55035 ?iv . }
  FILTER NOT EXISTS { ?thr orkgp:P55034 ?ev . }
  FILTER NOT EXISTS { ?thr orkgp:P55036 ?clv . }
  FILTER NOT EXISTS { ?thr orkgp:P59109 ?rel . }
  FILTER NOT EXISTS { ?thr orkgp:P60006 ?gen . }
  FILTER NOT EXISTS { ?thr orkgp:P97002 ?rep . }
  FILTER NOT EXISTS { ?thr orkgp:P68005 ?cont . }
  FILTER NOT EXISTS { ?thr orkgp:P97000 ?desc . }
  FILTER NOT EXISTS { ?thr orkgp:P97001 ?theo . }
  ?mentioned rdfs:label ?mentionedLabel .
}
ORDER BY ?mentionedLabel

SELECT DISTINCT ?paper ?paperLabel ?venue ?venueLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001 .
    ?contribution orkgp:P135046 ?venue .

    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?venue rdfs:label ?venueLabel . }
}
ORDER BY ?paperLabel ?venueLabel

SELECT DISTINCT ?paper ?paperLabel ?researchParadigm ?researchParadigmLabel
WHERE {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C27001.               
    ?contribution orkgp:P57003 ?researchParadigm .
    ?contribution orkgp:P135046 ?venue .
    ?venue rdfs:label ?venue_name .

    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
    OPTIONAL { ?paper rdfs:label ?paperLabel . }
    OPTIONAL { ?researchParadigm rdfs:label ?researchParadigmLabel . }
